import express from 'express';
import cors from 'cors';
import dotenv from 'dotenv';
import axios from 'axios';
import { fileURLToPath } from 'url';
import path from 'path';
import fs from 'fs';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

dotenv.config();

const app = express();
const PORT = process.env.QUICKCASH_PORT || 3001;

app.use(cors());
app.use(express.json());

// API Key validation middleware
const validateApiKey = (req, res, next) => {
  const apiKey = req.headers['x-api-key'];
  const validKey = process.env.QUICKCASH_API_KEY || process.env.ANTHROPIC_API_KEY;
  
  if (!apiKey || apiKey !== validKey) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  next();
};

// Health check
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// SendGrid Email API
app.post('/api/send-email', validateApiKey, async (req, res) => {
  try {
    const { to, subject, content, from } = req.body;
    
    const sendgridKey = process.env.SENDGRID_API_KEY;
    if (!sendgridKey) {
      return res.status(400).json({ error: 'SendGrid API key not configured' });
    }

    const response = await axios.post('https://api.sendgrid.com/v3/mail/send', {
      personalizations: [{
        to: [{ email: to }],
        subject: subject
      }],
      from: { email: from || process.env.SENDGRID_FROM_EMAIL },
      content: [{
        type: 'text/plain',
        value: content
      }]
    }, {
      headers: {
        'Authorization': `Bearer ${sendgridKey}`,
        'Content-Type': 'application/json'
      }
    });

    res.json({ success: true, messageId: response.headers['x-message-id'] });
  } catch (error) {
    console.error('SendGrid error:', error.response?.data || error.message);
    res.status(500).json({ error: error.response?.data || 'Failed to send email' });
  }
});

// Apollo.io Lead Generation API
app.post('/api/apollo-leads', validateApiKey, async (req, res) => {
  try {
    const { industry, location, limit = 10 } = req.body;
    
    const apolloKey = process.env.APOLLO_API_KEY;
    if (!apolloKey) {
      return res.status(400).json({ error: 'Apollo API key not configured' });
    }

    const response = await axios.post('https://api.apollo.io/v1/mixed_people/search', {
      q_keywords: industry,
      location_hierarchy: [location],
      page: 1,
      per_page: limit
    }, {
      headers: {
        'Api-Key': apolloKey,
        'Content-Type': 'application/json'
      }
    });

    const leads = response.data.people?.map(person => ({
      name: `${person.first_name} ${person.last_name}`,
      email: person.email,
      company: person.organization?.name,
      title: person.title,
      linkedin: person.linkedin_url
    })) || [];

    res.json({ success: true, leads, count: leads.length });
  } catch (error) {
    console.error('Apollo error:', error.response?.data || error.message);
    res.status(500).json({ error: error.response?.data || 'Failed to fetch leads' });
  }
});

// Clearbit Enrichment API
app.post('/api/clearbit-enrich', validateApiKey, async (req, res) => {
  try {
    const { email } = req.body;
    
    if (!process.env.CLEARBIT_API_KEY) {
      return res.status(400).json({ error: 'Clearbit API key not configured' });
    }

    const response = await axios.get(`https://person.clearbit.com/v2/combined/find`, {
      params: { email: email },
      headers: {
        'Authorization': `Bearer ${process.env.CLEARBIT_API_KEY}`
      }
    });

    res.json({ success: true, data: response.data });
  } catch (error) {
    console.error('Clearbit error:', error.response?.data || error.message);
    res.status(500).json({ error: error.response?.data || 'Failed to enrich data' });
  }
});

// Upwork API (OAuth2 flow would be needed for full integration)
app.post('/api/upwork-jobs', validateApiKey, async (req, res) => {
  try {
    const { skill, limit = 10 } = req.body;
    
    const upworkToken = process.env.UPWORK_ACCESS_TOKEN;
    if (!upworkToken) {
      // Return mock data for testing since OAuth2 is not configured
      return res.json({ 
        success: true, 
        jobs: [
          { title: `${skill} needed`, budget: '$50-100', link: '#' },
          { title: `Expert ${skill} required`, budget: '$100-500', link: '#' },
          { title: `${skill} project`, budget: '$500-1000', link: '#' }
        ]
      });
    }

    const response = await axios.get('https://www.upwork.com/api/profiles/v2/search/jobs', {
      params: {
        q: skill,
        limit: limit
      },
      headers: {
        'Authorization': `Bearer ${upworkToken}`
      }
    });

    res.json({ success: true, jobs: response.data.jobs });
  } catch (error) {
    console.error('Upwork error:', error.response?.data || error.message);
    res.status(500).json({ error: error.response?.data || 'Failed to fetch jobs' });
  }
});

// Stripe Payment Intent
app.post('/api/stripe-payment', validateApiKey, async (req, res) => {
  try {
    const { amount, currency = 'usd', description } = req.body;
    
    if (!process.env.STRIPE_SECRET_KEY) {
      return res.status(400).json({ error: 'Stripe secret key not configured' });
    }

    const response = await axios.post('https://api.stripe.com/v1/payment_intents', {
      amount: Math.round(amount * 100), // Convert to cents
      currency: currency,
      description: description
    }, {
      headers: {
        'Authorization': `Bearer ${process.env.STRIPE_SECRET_KEY}`,
        'Content-Type': 'application/x-www-form-urlencoded'
      }
    });

    res.json({ success: true, clientSecret: response.data.client_secret });
  } catch (error) {
    console.error('Stripe error:', error.response?.data || error.message);
    res.status(500).json({ error: error.response?.data || 'Failed to create payment intent' });
  }
});

// Claude API proxy (for secure key management)
app.post('/api/claude', validateApiKey, async (req, res) => {
  try {
    const { prompt, model = 'claude-sonnet-4-20250514', maxTokens = 1000 } = req.body;
    
    const anthropicKey = process.env.ANTHROPIC_API_KEY;
    if (!anthropicKey) {
      return res.status(400).json({ error: 'Anthropic API key not configured' });
    }

    const response = await axios.post('https://api.anthropic.com/v1/messages', {
      model: model,
      max_tokens: maxTokens,
      messages: [{ role: 'user', content: prompt }]
    }, {
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': anthropicKey,
        'anthropic-version': '2023-06-01'
      }
    });

    res.json({
      success: true,
      text: response.data.content[0].text,
      inputTokens: response.data.usage?.input_tokens || 0,
      outputTokens: response.data.usage?.output_tokens || 0
    });
  } catch (error) {
    console.error('Claude error:', error.response?.data || error.message);
    res.status(500).json({ error: error.response?.data || 'Failed to call Claude API' });
  }
});

// QuickCash Tool Endpoints
app.post('/api/quickcash/1', validateApiKey, async (req, res) => {
  try {
    const { service, price, turnaround } = req.body;
    
    const anthropicKey = process.env.ANTHROPIC_API_KEY;
    if (!anthropicKey) {
      return res.status(400).json({ error: 'Anthropic API key not configured' });
    }

    const prompt = `Generate a professional ${service} offering with ${turnaround} hour turnaround, priced at $${price}. Include:
1. A compelling title
2. Detailed description
3. Key features/benefits
4. Deliverables list
5. Pricing breakdown`;

    const response = await axios.post('https://api.anthropic.com/v1/messages', {
      model: 'claude-sonnet-4-20250514',
      max_tokens: 2000,
      messages: [{ role: 'user', content: prompt }]
    }, {
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': anthropicKey,
        'anthropic-version': '2023-06-01'
      }
    });

    res.json({
      output: response.data.content[0].text,
      stats: {
        calls: 1,
        inputTokens: response.data.usage?.input_tokens || 0,
        outputTokens: response.data.usage?.output_tokens || 0,
        cost: ((response.data.usage?.input_tokens || 0) / 1_000_000 * 3.0 + (response.data.usage?.output_tokens || 0) / 1_000_000 * 15.0)
      }
    });
  } catch (error) {
    console.error('QuickCash Tool 1 error:', error.response?.data || error.message);
    res.status(500).json({ error: error.response?.data || 'Failed to generate service offering' });
  }
});

